import React, { useEffect, useState } from 'react';

const storageKey = 'ship.uploadTracker.activeUploads';

export interface UploadTrackerEntry {
  id: string;
  label?: string;
  startedAt: number;
}

export interface UploadTrackerState {
  activeUploads: UploadTrackerEntry[];
}

export type UploadTrackerListener = (state: UploadTrackerState) => void;

const activeUploads = new Map<string, UploadTrackerEntry>();
const listeners = new Set<UploadTrackerListener>();

function persistState() {
  if (typeof window === 'undefined') {
    return;
  }

  window.sessionStorage.setItem(storageKey, JSON.stringify(getUploadTrackerState()));
}

function emit() {
  persistState();
  const snapshot = getUploadTrackerState();
  listeners.forEach((listener) => listener(snapshot));
}

export function getUploadTrackerState(): UploadTrackerState {
  return {
    activeUploads: [...activeUploads.values()].sort((a, b) => a.startedAt - b.startedAt),
  };
}

export function hasActiveUploads(): boolean {
  return activeUploads.size > 0;
}

export function subscribeUploadTracker(listener: UploadTrackerListener): () => void {
  listeners.add(listener);
  listener(getUploadTrackerState());
  return () => {
    listeners.delete(listener);
  };
}

export function startUploadTracking(id: string, label?: string): () => void {
  activeUploads.set(id, { id, label, startedAt: Date.now() });
  emit();
  return () => {
    if (activeUploads.delete(id)) {
      emit();
    }
  };
}

export function trackUpload<T>(id: string, task: () => Promise<T>, label?: string): Promise<T> {
  const stop = startUploadTracking(id, label);
  return task().finally(stop);
}

function useUploadTrackerState() {
  const [state, setState] = useState<UploadTrackerState>(() => getUploadTrackerState());

  useEffect(() => subscribeUploadTracker(setState), []);

  return state;
}

export function UploadNavigationWarning(props: { message?: string; when?: boolean }): null {
  const { message = 'You have uploads in progress. Leaving now may cancel them.', when } = props;
  const state = useUploadTrackerState();
  const enabled = when ?? state.activeUploads.length > 0;

  useEffect(() => {
    if (!enabled || typeof window === 'undefined') {
      return;
    }

    const handleBeforeUnload = (event: BeforeUnloadEvent) => {
      event.preventDefault();
      event.returnValue = message;
      return message;
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [enabled, message]);

  return null;
}

