import { beforeEach, describe, expect, it, vi } from 'vitest';
import { clearUploads, getUploadCount, getUploadNavigationWarningHookState, registerUpload, updateUploadProgress } from './uploadTracker';
import { createUploadProgressTracker, trackUploadProgress } from './upload';

const realWindow = globalThis.window;

describe('upload progress tracking', () => {
  beforeEach(() => {
    clearUploads();
  });

  it('clamps progress values before notifying callbacks', () => {
    const onProgress = vi.fn();

    trackUploadProgress(onProgress, {
      fileId: 'file-1',
      progress: 133,
      status: 'uploading',
    });

    expect(onProgress).toHaveBeenCalledWith({
      fileId: 'file-1',
      progress: 100,
      status: 'uploading',
    });
  });

  it('updates tracker state as progress changes', () => {
    const tracker = createUploadProgressTracker();

    tracker.update({ fileId: 'file-1', progress: 5, status: 'pending' });
    tracker.update({ progress: 42, status: 'uploading' });

    expect(tracker.getState()).toEqual({
      fileId: 'file-1',
      progress: 42,
      status: 'uploading',
    });
  });
});

describe('upload tracker navigation warning behavior', () => {
  beforeEach(() => {
    clearUploads();
    globalThis.window = realWindow;
  });

  it('exposes a blocked warning state when uploads are active and clears on proceed', () => {
    registerUpload('upload-1', 'demo.pdf');
    updateUploadProgress('upload-1', 55);

    const warning = getUploadNavigationWarningHookState();
    expect(warning.isBlocked).toBe(true);
    expect(warning.isOpen).toBe(true);
    expect(warning.message).toBe('1 upload is still in progress.');
    expect(getUploadCount()).toBe(1);

    warning.proceed();
    expect(getUploadCount()).toBe(0);
    expect(getUploadNavigationWarningHookState().isBlocked).toBe(false);
  });
});

