  await pool.query(`UPDATE files SET status = 'uploaded', uploaded_at = now(), error_message = NULL WHERE id = $1 AND workspace_id = $2`, [parsed.data, req.workspaceId]);

  return res.status(200).json({ id: file.id, filename: file.filename, mimeType: file.mime_type, sizeBytes: Number(file.size_bytes), status: 'uploaded', downloadUrl: getLocalDownloadUrl(file.id, file.filename), uploadType: 'local', uploadedAt: new Date().toISOString() });
});

router.get('/:id', authMiddleware, async (req: Request, res: Response) => {
  const parsed = fileIdSchema.safeParse(req.params.id);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid file ID format' });

  const result = await pool.query(`SELECT id, filename, mime_type, size_bytes, status, created_at, uploaded_at, failed_at, error_message, s3_key FROM files WHERE id = $1 AND workspace_id = $2`, [parsed.data, req.workspaceId]);
