router.post('/upload/:id', authMiddleware, async (req: Request, res: Response) => {
  const parsed = fileIdSchema.safeParse(req.params.id);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid file ID format' });
  if (useS3Storage) return res.status(400).json({ error: 'Local upload endpoint is disabled when S3 storage is enabled' });

  const fileResult = await pool.query(`SELECT id, filename, mime_type, size_bytes, s3_key, status FROM files WHERE id = $1 AND workspace_id = $2`, [parsed.data, req.workspaceId]);
  const file = fileResult.rows[0] as UploadedFileRecord | undefined;
  if (!file) return res.status(404).json({ error: 'File not found' });
  if (file.status !== 'pending') return res.status(409).json({ error: 'File has already been uploaded' });

  const multipart = getMultipartFile(req);
  if (!multipart) return res.status(400).json({ error: 'No uploaded file found' });
  const metadata = uploadMetadataSchema.safeParse(multipart);
  if (!metadata.success) return res.status(400).json({ error: 'Invalid upload payload', details: metadata.error.flatten() });
  if (metadata.data.sizeBytes > MAX_FILE_SIZE_BYTES) return res.status(413).json({ error: 'File exceeds 1GB limit' });
  if (isDangerousFilename(metadata.data.filename) || isDangerousFilename(file.filename)) return res.status(400).json({ error: 'File type not allowed' });

  mkdirSync(localUploadRootResolved, { recursive: true });
  writeFileSync(getLocalUploadPath(file.s3_key), metadata.data.buffer);
  await pool.query(`UPDATE files SET status = 'uploaded', uploaded_at = now(), error_message = NULL WHERE id = $1 AND workspace_id = $2`, [parsed.data, req.workspaceId]);

  const downloadUrl = getLocalDownloadUrl(file.id, file.filename);
  return res.status(200).json({ id: file.id, filename: file.filename, mimeType: file.mime_type, sizeBytes: Number(file.size_bytes), status: 'uploaded', downloadUrl, uploadType: 'local', uploadedAt: new Date().toISOString() });
});

