{"success":true,"content":"     1	// In development, Vite proxy handles /api routes (see vite.config.ts)
     2	// In production, use VITE_API_URL or relative URLs
     3	const API_URL = import.meta.env.VITE_API_URL ?? '';
     4	
     5	interface ApiResponse<T> {
     6	  success: boolean;
     7	  data?: T;
     8	  error?: {
     9	    code: string;
    10	    message: string;
    11	  };
    12	}
    13	
    14	// CSRF token cache for state-changing requests
    15	let csrfToken: string | null = null;
    16	
    17	// Helper: Check if response has JSON content type
    18	function isJsonResponse(response: Response): boolean {
    19	  const contentType = response.headers.get('content-type');
    20	  return contentType?.includes('application/json') ?? false;
    21	}
    22	
    23	/**
    24	 * Handle session expiration - redirect to login with expired=true flag
    25	 *
    26	 * IMPORTANT: Only call this for actual session expiration (SESSION_EXPIRED error code),
    27	 * NOT for missing sessions (UNAUTHORIZED). Fresh visitors with no session should get
    28	 * a clean redirect via ProtectedRoute without the "session expired" message.
    29	 *
    30	 * The expired=true flag triggers the yellow "session expired" modal on the login page.
    31	 * Fresh visitors shouldn't see this - it would be confusing UX.
    32	 *
    33	 * Returns `never` because it always redirects or throws.
    34	 */
    35	function handleSessionExpired(): never {
    36	  // Don't redirect to login when offline - let TanStack Query handle retries
    37	  if (!navigator.onLine) {
    38	    throw new Error('Network offline - request failed');
    39	  }
    40	  // Don't redirect on public routes like /invite - they work without authentication
    41	  if (window.location.pathname.startsWith('/invite')) {
    42	    throw new Error('Session check failed - continuing on public route');
    43	  }
    44	  if (window.location.pathname !== '/login') {
    45	    const returnTo = encodeURIComponent(
    46	      window.location.pathname + window.location.search + window.location.hash
    47	    );
    48	    window.location.href = `/login?expired=true&returnTo=${returnTo}`;
    49	  }
    50	  // Throw to satisfy TypeScript's `never` type (redirect is async)
    51	  throw new Error('Session expired - redirecting to login');
    52	}
    53	
    54	async function ensureCsrfToken(): Promise<string> {
    55	  if (!csrfToken) {
    56	    const response = await fetch(`${API_URL}/api/csrf-token`, {
    57	      credentials: 'include',
    58	    });
    59	    if (!response.ok || !isJsonResponse(response)) {
    60	      // Session likely expired - redirect to login
    61	      if (response.status === 401 || response.status === 403) {
    62	        handleSessionExpired(); // never returns
    63	      }
    64	      throw new Error('Failed to get CSRF token');
    65	    }
    66	    const data = await response.json();
    67	    csrfToken = data.token;
    68	  }
    69	  return csrfToken!;
    70	}
    71	
    72	// Clear CSRF token on logout or session change
    73	export function clearCsrfToken(): void {
    74	  csrfToken = null;
    75	}
    76	
    77	// Simple helpers that return Response objects (for contexts that need res.ok checks)
    78	async function fetchWithCsrf(
    79	  endpoint: string,
    80	  method: 'POST' | 'PUT' | 'PATCH' | 'DELETE',
    81	  body?: object
    82	): Promise<Response> {
    83	  const token = await ensureCsrfToken();
    84	  const res = await fetch(`${API_URL}${endpoint}`, {
    85	    method,
    86	    headers: {
    87	      'Content-Type': 'application/json',
    88	      'X-CSRF-Token': token,
    89	    },
    90	    credentials: 'include',
    91	    body: body ? JSON.stringify(body) : undefined,
    92	  });
    93	
    94	  const isJson = isJsonResponse(res);
    95	
    96	  // CloudFront intercepts 403s and returns HTML - detect and redirect to login
    97	  if (res.status === 403 && !isJson) {
    98	    handleSessionExpired(); // never returns
    99	  }
   100	
   101	  // If CSRF token invalid (403 with JSON), retry once
   102	  if (res.status === 403 && isJson) {
   103	    clearCsrfToken();
   104	    const newToken = await ensureCsrfToken();
   105	    return fetch(`${API_URL}${endpoint}`, {
   106	      method,
   107	      headers: {
   108	        'Content-Type': 'application/json',
   109	        'X-CSRF-Token': newToken,
   110	      },
   111	      credentials: 'include',
   112	      body: body ? JSON.stringify(body) : undefined,
   113	    });
   114	  }
   115	  return res;
   116	}
   117	
   118	export async function apiGet(endpoint: string): Promise<Response> {
   119	  const res = await fetch(`${API_URL}${endpoint}`, {
   120	    credentials: 'include',
   121	  });
   122	
   123	  // Handle session expiration - redirect to login
   124	  if (res.status === 401) {
   125	    handleSessionExpired(); // never returns
   126	  }
   127	
   128	  // Check for non-JSON response (CloudFront HTML interception)
   129	  // This can happen when:
   130	  // 1. CDN serves HTML error page for non-existent routes
   131	  // 2. Session expired and CloudFront returns login page
   132	  // 3. Route misconfiguration serving index.html for API routes
   133	  if (!isJsonResponse(res)) {
   134	    // Non-200 + non-JSON = likely session issue (CloudFront 403 interception)
   135	    if (res.status !== 200) {
   136	      handleSessionExpired(); // never returns
   137	    }
   138	    // 200 + non-JSON = likely routing/CDN misconfiguration
   139	    // Don't redirect to login (not a session issue), throw error for React Query to handle
   140	    throw new Error(`API returned HTML instead of JSON for ${endpoint}. This may indicate a routing or CDN configuration issue.`);
   141	  }
   142	
   143	  return res;
   144	}
   145	
   146	export async function apiPost(endpoint: string, body?: object): Promise<Response> {
   147	  return fetchWithCsrf(endpoint, 'POST', body);
   148	}
   149	
   150	export async function apiPut(endpoint: string, body?: object): Promise<Response> {
   151	  return fetchWithCsrf(endpoint, 'PUT', body);
   152	}
   153	
   154	export async function apiPatch(endpoint: string, body: object): Promise<Response> {
   155	  return fetchWithCsrf(endpoint, 'PATCH', body);
   156	}
   157	
   158	export async function apiDelete(endpoint: string, body?: object): Promise<Response> {
   159	  return fetchWithCsrf(endpoint, 'DELETE', body);
   160	}
   161	
   162	async function request<T>(
   163	  endpoint: string,
   164	  options: RequestInit = {}
   165	): Promise<ApiResponse<T>> {
   166	  const headers: Record<string, string> = {
   167	    'Content-Type': 'application/json',
   168	    ...(options.headers as Record<string, string>),
   169	  };
   170	
   171	  // Add CSRF token for state-changing requests
   172	  const method = options.method?.toUpperCase() || 'GET';
   173	  if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(method)) {
   174	    const token = await ensureCsrfToken();
   175	    headers['X-CSRF-Token'] = token;
   176	  }
   177	
   178	  const response = await fetch(`${API_URL}${endpoint}`, {
   179	    ...options,
   180	    credentials: 'include',
   181	    headers,
   182	  });
   183	
   184	  // CloudFront may intercept errors and return HTML - detect and redirect
   185	  if (!isJsonResponse(response)) {
   186	    // On public routes like /invite, return error response instead of redirecting
   187	    if (window.location.pathname.startsWith('/invite')) {
   188	      return {
   189	        success: false,
   190	        error: { code: 'NETWORK_ERROR', message: 'Server returned non-JSON response' },
   191	      } as ApiResponse<T>;
   192	    }
   193	    handleSessionExpired(); // never returns
   194	  }
   195	
   196	  const data: ApiResponse<T> = await response.json();
   197	
