import { describe, it, expect } from 'vitest';
import { Editor } from '@tiptap/core';
import StarterKit from '@tiptap/starter-kit';
import { CommentMark } from './CommentMark.ts';
import { CommentDisplayExtension } from './CommentDisplay.tsx';

const baseContent = {
  type: 'doc',
  content: [
    {
      type: 'paragraph',
      content: [{ type: 'text', text: 'Threaded text', marks: [{ type: 'commentMark', attrs: { commentId: 'thread-1' } }] }],
    },
  ],
};

describe('CommentDisplayExtension', () => {
  it('renders resolved threads with resolved_at state reflected in HTML', () => {
    const editor = new Editor({
      extensions: [StarterKit, CommentMark, CommentDisplayExtension.configure({})],
      content: baseContent,
    });

    editor.extensionStorage.commentDisplay.comments = [
      {
        id: 'thread-1',
        documentId: 'doc-1',
        parentId: null,
        content: 'Root comment',
        status: 'resolved',
        createdAt: '2025-01-01T00:00:00.000Z',
        updatedAt: '2025-01-01T00:00:00.000Z',
        resolvedAt: '2025-01-02T00:00:00.000Z',
        resolvedById: 'user-1',
        replies: [],
      },
    ];

    const html = editor.getHTML();
    expect(html).toContain('Threaded text');
    expect(html).toContain('comment-highlight');
    editor.destroy();
  });
});

import { describe, it, expect, vi } from 'vitest';
import { Editor } from '@tiptap/core';
import StarterKit from '@tiptap/starter-kit';
import Image from '@tiptap/extension-image';
import { CommentMark } from './CommentMark.ts';
import { CommentDisplayExtension } from './CommentDisplay.tsx';
import { ImageUploadExtension } from './ImageUpload.tsx';

describe('Document editor wiring', () => {
  it('embeds uploaded image urls in document flow and keeps comment thread hooks available', () => {
    const editor = new Editor({
      extensions: [StarterKit, Image, CommentMark, ImageUploadExtension.configure(), CommentDisplayExtension.configure({})],
      content: {
        type: 'doc',
        content: [
          { type: 'paragraph', content: [{ type: 'text', text: 'Intro' }] },
          {
            type: 'image',
            attrs: {
              src: 'https://cdn.example.com/uploaded.png',
              alt: 'uploaded image',
              title: 'uploaded image',
            },
          },
          {
            type: 'paragraph',
            content: [{ type: 'text', text: 'Commented', marks: [{ type: 'commentMark', attrs: { commentId: 'thread-1' } }] }],
          },
        ],
      },
    });

    const html = editor.getHTML();
    expect(html).toContain('https://cdn.example.com/uploaded.png');
    expect(html).toContain('Commented');
    expect(html).toContain('comment-highlight');
    editor.destroy();
  });
});

