commentsRouter.get('/documents/:id/comments', authMiddleware, async (req: Request, res: Response) => {
  const documentId = parseUuid(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  const workspaceId = req.workspaceId;
  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });
  if (!(await canAccessDocument(documentId, workspaceId))) return res.status(404).json({ error: 'Document not found' });

  const rows = await loadThreadComments(documentId);
  const threads = new Map<string, CommentThreadResponse>();
  for (const row of rows.rows) {
    const comment = mapCommentRow(row);
    const thread = threads.get(comment.comment_id) ?? { comment_id: comment.comment_id, root: null, replies: [] };
    if (comment.parent_id === null) thread.root = comment;
    else thread.replies.push(comment);
    threads.set(comment.comment_id, thread);
  }

  const comments = Array.from(threads.values()).sort((a, b) => threadSortValue(a).localeCompare(threadSortValue(b)));
  return res.json({ comments });
});

