{"success":true,"content":"     1	import { Router, type Request, type Response } from 'express';
     2	import { z } from 'zod';
     3	import { pool } from '../db/client.js';
     4	import { authMiddleware } from '../middleware/auth.js';
     5	
     6	const router = Router();
     7	
     8	const uuidParamSchema = z.string().uuid();
     9	const documentLinkSyncRequestSchema = z
    10	  .object({
    11	    target_ids: z.array(z.string().uuid()).optional(),
    12	    links: z.array(z.string().uuid()).optional(),
    13	    mentions: z.array(z.string().uuid()).optional(),
    14	    extracted_links: z.array(z.string().uuid()).optional(),
    15	    extracted_mentions: z.array(z.string().uuid()).optional(),
    16	  })
    17	  .passthrough();
    18	
    19	type BacklinkSummary = {
    20	  id: string;
    21	  title: string;
    22	  type: string;
    23	};
    24	
    25	type LinkSyncResponse = {
    26	  success: boolean;
    27	  document_id: string;
    28	  linked_document_ids: string[];
    29	};
    30	
    31	function buildSyncedLinkSet(payload: z.infer<typeof documentLinkSyncRequestSchema>) {
    32	  return Array.from(
    33	    new Set([
    34	      ...(payload.target_ids ?? []),
    35	      ...(payload.links ?? []),
    36	      ...(payload.mentions ?? []),
    37	      ...(payload.extracted_links ?? []),
    38	      ...(payload.extracted_mentions ?? []),
    39	    ])
    40	  );
    41	}
    42	
    43	async function ensureDocumentExistsForWorkspace(docId: string, workspaceId: string) {
    44	  const result = await pool.query(
    45	    `SELECT id FROM documents
    46	     WHERE id = $1
    47	       AND workspace_id = $2
    48	       AND deleted_at IS NULL`,
    49	    [docId, workspaceId]
    50	  );
    51	
    52	  return result.rows.length > 0;
    53	}
    54	
    55	router.get('/:id/backlinks', authMiddleware, async (req: Request, res: Response) => {
    56	  const parsedId = uuidParamSchema.safeParse(req.params.id);
    57	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
    58	
    59	  const workspaceId = req.workspaceId;
    60	  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });
    61	
    62	  const documentExists = await ensureDocumentExistsForWorkspace(parsedId.data, workspaceId);
    63	  if (!documentExists) return res.status(404).json({ error: 'Document not found' });
    64	
    65	  const result = await pool.query(
    66	    `SELECT d.id, COALESCE(d.document_type, 'document') AS document_type, d.title
    67	     FROM document_links dl
    68	     JOIN documents d ON dl.source_id = d.id
    69	     WHERE dl.target_id = $1
    70	       AND d.workspace_id = $2
    71	       AND d.deleted_at IS NULL
    72	       AND d.archived_at IS NULL
    73	     ORDER BY dl.created_at DESC, d.created_at DESC`,
    74	    [parsedId.data, workspaceId]
    75	  );
    76	
    77	  const backlinks = result.rows.map((row) => ({
    78	    id: row.id,
    79	    title: row.title,
    80	    type: row.document_type,
    81	  }));
    82	
    83	  return res.json(backlinks);
    84	});
    85	
    86	router.post('/:id/links', authMiddleware, async (req: Request, res: Response) => {
    87	  const parsedId = uuidParamSchema.safeParse(req.params.id);
    88	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
    89	
    90	  const workspaceId = req.workspaceId;
    91	  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });
    92	
    93	  const parsed = documentLinkSyncRequestSchema.safeParse(req.body);
    94	  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });
    95	
    96	  const sourceId = parsedId.data;
    97	  const sourceExists = await ensureDocumentExistsForWorkspace(sourceId, workspaceId);
    98	  if (!sourceExists) return res.status(404).json({ error: 'Document not found' });
    99	
   100	  const extractedIds = buildSyncedLinkSet(parsed.data).filter((id) => id !== sourceId);
   101	  const uniqueExtractedIds = Array.from(new Set(extractedIds));
   102	
   103	  const targetsResult = uniqueExtractedIds.length
   104	    ? await pool.query(
   105	        `SELECT id FROM documents
   106	         WHERE id = ANY($1::uuid[])
   107	           AND workspace_id = $2
   108	           AND deleted_at IS NULL
   109	           AND archived_at IS NULL`,
   110	        [uniqueExtractedIds, workspaceId]
   111	      )
   112	    : { rows: [] as Array<{ id: string }> };
   113	
   114	  if (targetsResult.rows.length !== uniqueExtractedIds.length) {
   115	    return res.status(400).json({ error: 'One or more target documents not found' });
   116	  }
   117	
   118	  const client = await pool.connect();
   119	  try {
   120	    await client.query('BEGIN');
   121	    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
   122	
   123	    if (uniqueExtractedIds.length > 0) {
   124	      const values = uniqueExtractedIds
   125	        .map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`)
   126	        .join(', ');
   127	      const params = uniqueExtractedIds.flatMap((targetId) => [sourceId, targetId]);
   128	      await client.query(
   129	        `INSERT INTO document_links (source_id, target_id)
   130	         VALUES ${values}
   131	         ON CONFLICT (source_id, target_id) DO UPDATE SET updated_at = NOW()`,
   132	        params
   133	      );
   134	    }
   135	
   136	    const responseRows = await client.query(
   137	      `SELECT DISTINCT target_id
   138	       FROM document_links
   139	       WHERE source_id = $1
   140	       ORDER BY target_id ASC`,
   141	      [sourceId]
   142	    );
   143	
   144	    await client.query('COMMIT');
   145	    return res.status(200).json({
   146	      success: true,
   147	      document_id: sourceId,
   148	      linked_document_ids: responseRows.rows.map((row) => row.target_id),
   149	      target_ids: responseRows.rows.map((row) => row.target_id),
   150	    } satisfies LinkSyncResponse & { target_ids: string[] });
   151	  } catch (err) {
   152	    await client.query('ROLLBACK');
   153	    throw err;
   154	  } finally {
   155	    client.release();
   156	  }
   157	});
