    31	    triggerImageUpload(editorRef.current);
    32	  }, []);
    33	
    34	  const handleReply = useCallback(async (commentId: string, content: string) => {
    35	    await replyToComment({ documentId, parentId: commentId, content });
    36	  }, [documentId, replyToComment]);
    37	
    38	  const handleResolve = useCallback(async (commentId: string, resolved: boolean) => {
    39	    await resolveComment({ commentId, resolved });
    40	    if (resolved && commentId === pendingCommentId) setPendingCommentId(null);
    41	  }, [pendingCommentId, resolveComment]);
    42	
    43	  const handleCreateComment = useCallback(async () => {
    44	    if (!editorRef.current || !pendingSelection) return;
    45	    const commentId = crypto.randomUUID();
    46	    editorRef.current.chain().focus().setTextSelection(pendingSelection).setComment(commentId).run();
    47	    setPendingCommentId(commentId);
    48	    await createComment({ documentId, content: 'New comment thread', commentId });
    49	  }, [createComment, documentId, pendingSelection]);
    50	
    51	  const handleSyncLinks = useCallback(async () => {
    52	    if (!editorRef.current) return;
    53	
    54	    const payload = editorRef.current.getJSON();
    55	    const response = await apiPost<LinkSyncResponse>(`/api/documents/${documentId}/links/sync`, {
    56	      content: payload,
    57	    });
    58	
    59	    const nextContent = (response.data ?? response.backlinks ?? payload) as unknown;
    60	    onContentChange?.(nextContent);
    61	  }, [documentId, onContentChange]);
    62	
    63	  const editor = useEditor({
    64	    extensions: [
    65	      StarterKit,
    66	      Image,
    67	      CommentMark.configure({
    68	        onCreateThread: (commentId) => {
    69	          setPendingCommentId(commentId);
    70	        },
    71	      }),
    72	      ImageUploadExtension,
    73	      CommentDisplayExtension.configure({
    74	        onReply: handleReply,
    75	        onResolve: handleResolve,
    76	        onCreateThread: (commentId) => setPendingCommentId(commentId),
    77	      }),
    78	    ],
    79	    content,
    80	    onUpdate: ({ editor }) => {
    81	      onContentChange?.(editor.getJSON());
    82	    },
    83	    onSelectionUpdate: ({ editor }) => {
