    89	
    90	  useEffect(() => {
    91	    editorRef.current = editor;
    92	  }, [editor]);
    93	
    94	  const commentsCount = useMemo(() => comments.reduce((count: number, thread: CommentThread) => count + (thread.replies?.length || 0) + 1, 0), [comments]);
    95	
    96	  return (
    97	    <div className="flex h-full flex-col gap-2">
    98	      <div className="flex items-center gap-2 border-b border-border pb-2">
    99	        <button type="button" className="rounded bg-primary px-3 py-1 text-sm text-primary-foreground" onClick={handleUploadImage}>
   100	          Upload image
   101	        </button>
   102	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={handleCreateComment} disabled={!pendingSelection}>
   103	          Add comment
   104	        </button>
   105	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={handleSyncLinks}>
   106	          Sync links
   107	        </button>
   108	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={() => pendingCommentId && handleResolve(pendingCommentId, true)} disabled={!pendingCommentId}>
   109	          Resolve latest
   110	        </button>
   111	        <span className="text-xs text-muted">{commentsCount} comment entries</span>
   112	      </div>
   113	      <EditorContent editor={editor} />
   114	    </div>
   115	  );
   116	}
