    85	async function getCsrfToken(): Promise<string> {
    86	  const res = await fetch(`${API_BASE}/api/csrf-token`, {
    87	    credentials: "include",
    88	  });
    89	  if (!res.ok) {
    90	    cachedCsrfTokenPromise = null;
    91	    if (res.status === 401 || res.status === 403) {
    92	      clearCsrfToken();
    93	    }
    94	    throw new Error("Failed to get CSRF token");
