   142	function unwrapMetadataEnvelope(
   143	  payload: FileMetadataEnvelope | FileMetadataResponse | null,
   144	): FileMetadataResponse | null {
   145	  if (!payload) return null;
   146	  if ("file" in payload && payload.file) return payload.file;
   147	  if ("data" in payload && payload.data) return payload.data;
