   167	export async function requestUpload(
   168	  file: File,
   169	  signal?: AbortSignal,
   170	): Promise<UploadRequestResult> {
   171	  const csrfToken = await getCsrfToken();
   172	  const mimeType = getUploadMimeType(file);
   173	
   174	  const payload: RequestUploadPayload = {
   175	    filename: file.name,
   176	    mimeType,
   177	    sizeBytes: file.size,
   178	  };
   179	
   180	  const res = await fetch(`${API_BASE}/api/files/upload-request`, {
   181	    method: "POST",
   182	    headers: {
   183	      "Content-Type": "application/json",
   184	      "X-CSRF-Token": csrfToken,
   185	    },
   186	    credentials: "include",
   187	    body: JSON.stringify(payload),
   188	    signal,
   189	  });
   190	
   191	  if (!res.ok) {
   192	    throw new Error(await getUploadErrorMessage(res, "Failed to create upload request"));
   193	  }
   194	
   195	  const data = (await res.json()) as UploadRequestResponse;
   196	  const fileId = data.file_id ?? data.file?.id ?? data.data?.id ?? "";
   197	  const uploadUrl = data.upload_url ?? "";
   198	  const cdnUrl = data.cdn_url ?? data.file?.cdn_url ?? data.data?.cdn_url;
   199	  const assetUrl =
   200	    data.asset_url ??
   201	    data.download_url ??
   202	    data.file?.download_url ??
   203	    data.data?.download_url ??
   204	    cdnUrl;
   205	  const isLocalUpload = Boolean(
   206	    data.is_local_upload ?? data.local_path ?? data.fields ??
   207	      uploadUrl.startsWith("/api/files/upload"),
   208	  );
   209	  return {
   210	    fileId,
   211	    uploadUrl,
   212	    cdnUrl,
   213	    method: data.method,
   214	    isLocalUpload,
   215	    localPath: data.local_path,
   216	    assetUrl,
   217	    downloadUrl: data.download_url,
   218	    fields: data.fields,
   219	  };
   220	}
   221	
   222	function getUploadMethod(request: UploadRequestResult): "PUT" | "POST" {
   223	  return request.method ?? (request.isLocalUpload ? "POST" : "PUT");
   224	}
   225	
   226	function isLocalUploadMethod(request: UploadRequestResult): boolean {
   227	  return (
   228	    request.isLocalUpload ?? request.uploadUrl.startsWith("/api/files/upload")
   229	  );
