    54	    window.removeEventListener('beforeunload', beforeUnloadListener);
    55	    beforeUnloadListener = null;
    56	  }
    57	
    58	  if (!hasActiveUploads()) return;
    59	
    60	  beforeUnloadListener = (event: BeforeUnloadEvent) => {
    61	    if (!hasActiveUploads()) return;
    62	    event.preventDefault();
    63	    event.returnValue = getUploadMessage(getUploadCount());
    64	    return event.returnValue;
    65	  };
    66	
    67	  window.addEventListener('beforeunload', beforeUnloadListener);
    68	}
