   136	export function getUploadNavigationWarningState(): UploadNavigationWarningState {
   137	  const snapshot = getUploadSnapshot();
   138	  return {
   139	    ...snapshot,
   140	    isBlocked: snapshot.uploadCount > 0,
   141	    proceed: clearUploads,
   142	    stay: () => undefined,
