   559	/** Get MIME type from filename extension as fallback */
   560	export function getMimeTypeFromExtension(filename: string): string | null {
   561	  const ext = filename.toLowerCase().slice(filename.lastIndexOf("."));
   562	  return EXTENSION_TO_MIME[ext] || null;
   563	}
