   565	/** Check if a file type is allowed for upload */
   566	export function isAllowedFileType(
   567	  mimeType: string,
   568	  filename?: string,
   569	): boolean {
   570	  if (!filename) return true;
   571	  const ext = filename.toLowerCase().slice(filename.lastIndexOf("."));
   572	  if (BLOCKED_EXTENSIONS.has(ext)) return false;
   573	  return true;
