     2	import { get, set, del, createStore } from 'idb-keyval';
     3	import type { PersistedClient, Persister } from '@tanstack/react-query-persist-client';
     4	
     5	// ===========================================
     6	// Cache Schema Versioning
     7	// ===========================================
     8	
     9	// Increment this when cache schema changes to auto-clear old data
    10	// v2: Removed local-first architecture (sync queues, pending mutations)
    11	export const CACHE_SCHEMA_VERSION = 2;
    12	
    13	// IndexedDB store for query cache
    14	const queryStore = createStore('ship-query-cache', 'queries');
    15	
    16	// IndexedDB store for metadata (schema version, etc)
    17	const metaStore = createStore('ship-meta', 'meta');
    18	
    19	// ===========================================
    20	// Schema Migration
    21	// ===========================================
    22	
    23	async function checkAndMigrateSchema(): Promise<void> {
    24	  try {
    25	    const storedVersion = await get<number>('schema_version', metaStore);
    26	
    27	    if (storedVersion === undefined) {
    28	      // First time - just set version
    29	      await set('schema_version', CACHE_SCHEMA_VERSION, metaStore);
    30	      console.log('[Schema] Initialized schema version:', CACHE_SCHEMA_VERSION);
    31	      return;
    32	    }
    33	
    34	    if (storedVersion !== CACHE_SCHEMA_VERSION) {
    35	      console.log('[Schema] Version mismatch:', storedVersion, '->', CACHE_SCHEMA_VERSION);
    36	      // Clear old cache data
    37	      await del('tanstack-query', queryStore);
    38	      // Update version
    39	      await set('schema_version', CACHE_SCHEMA_VERSION, metaStore);
    40	      console.log('[Schema] Cache cleared due to schema migration');
    41	    }
    42	  } catch (error) {
    43	    console.warn('[Schema] Migration check failed:', error);
    44	  }
    45	}
    46	
    47	// ===========================================
    48	// Cache Corruption Detection & Recovery
    49	// ===========================================
    50	
    51	let cacheCorrupted = false;
    52	let corruptionListeners: Array<(corrupted: boolean) => void> = [];
    53	
    54	// ===========================================
    55	// Mutation Error Events
    56	// ===========================================
    57	
    58	type MutationErrorListener = (error: Error, context: { operation?: string }) => void;
    59	let mutationErrorListeners: MutationErrorListener[] = [];
    60	
    61	export function subscribeToMutationErrors(listener: MutationErrorListener): () => void {
    62	  mutationErrorListeners.push(listener);
    63	  return () => {
    64	    mutationErrorListeners = mutationErrorListeners.filter(l => l !== listener);
    65	  };
    66	}
    67	
    68	function notifyMutationError(error: Error, context: { operation?: string }) {
    69	  mutationErrorListeners.forEach(l => l(error, context));
    70	}
    71	
    72	export function isCacheCorrupted(): boolean {
    73	  return cacheCorrupted;
    74	}
    75	
    76	export function subscribeToCacheCorruption(listener: (corrupted: boolean) => void): () => void {
    77	  corruptionListeners.push(listener);
    78	  if (cacheCorrupted) {
    79	    listener(true);
    80	  }
    81	  return () => {
    82	    corruptionListeners = corruptionListeners.filter(l => l !== listener);
    83	  };
    84	}
    85	
    86	function notifyCorruptionListeners(corrupted: boolean) {
    87	  cacheCorrupted = corrupted;
    88	  corruptionListeners.forEach(l => l(corrupted));
    89	}
    90	
    91	export async function clearAllCacheData(): Promise<void> {
    92	  try {
    93	    await del('tanstack-query', queryStore);
    94	    console.log('[Cache] Cleared all cache data');
    95	    notifyCorruptionListeners(false);
    96	  } catch (error) {
    97	    console.error('[Cache] Failed to clear cache:', error);
    98	    throw error;
    99	  }
   100	}
   101	
   102	// Create IndexedDB persister for TanStack Query with corruption detection
   103	export function createIDBPersister(): Persister {
   104	  return {
   105	    persistClient: async (client: PersistedClient) => {
   106	      try {
   107	        await set('tanstack-query', client, queryStore);
   108	      } catch (error) {
   109	        console.error('[Persister] Failed to persist client:', error);
   110	      }
   111	    },
   112	    restoreClient: async () => {
   113	      try {
   114	        const data = await get<PersistedClient>('tanstack-query', queryStore);
   115	        if (data && typeof data !== 'object') {
   116	          throw new Error('Invalid cache data structure');
   117	        }
   118	        return data;
   119	      } catch (error) {
   120	        console.error('[Persister] Cache corruption detected:', error);
   121	        notifyCorruptionListeners(true);
   122	        return undefined;
   123	      }
   124	    },
   125	    removeClient: async () => {
   126	      try {
   127	        await del('tanstack-query', queryStore);
   128	      } catch (error) {
   129	        console.error('[Persister] Failed to remove client:', error);
   130	      }
   131	    },
   132	  };
   133	}
   134	
   135	// Create the query client with stale-while-revalidate caching
   136	export const queryClient = new QueryClient({
   137	  defaultOptions: {
   138	    queries: {
   139	      staleTime: 1000 * 60 * 5, // 5 minutes
   140	      gcTime: 1000 * 60 * 60 * 24, // 24 hours
   141	      retry: (failureCount, error) => {
   142	        // Don't retry on 4xx errors (client errors)
   143	        if (error instanceof Error && 'status' in error) {
   144	          const status = (error as { status: number }).status;
   145	          if (status >= 400 && status < 500) return false;
   146	        }
   147	        return failureCount < 3;
   148	      },
   149	    },
   150	    mutations: {
   151	      retry: (failureCount, error) => {
   152	        // Don't retry on 4xx errors
   153	        if (error instanceof Error && 'status' in error) {
   154	          const status = (error as { status: number }).status;
   155	          if (status >= 400 && status < 500) return false;
