function getMultipartFile(req: Request): { buffer: Buffer; filename: string; mimeType: string; sizeBytes: number } {
  const anyReq = req as Request & { file?: unknown; files?: unknown };
  const candidate = anyReq.file ?? (Array.isArray(anyReq.files) ? anyReq.files[0] : undefined);
  const parsed = multipartFileSchema.safeParse(candidate);
  if (!parsed.success) {
    throw new Error('No uploaded file found');
  }
  return {
    buffer: parsed.data.buffer,
    filename: parsed.data.originalname,
    mimeType: parsed.data.mimetype,
    sizeBytes: parsed.data.size,
  };
}

