    38	function buildSyncedLinkSet(payload: z.infer<typeof documentLinkSyncRequestSchema>) {
    39	  return Array.from(
    40	    new Set([
    41	      ...(payload.target_ids ?? []),
    42	      ...(payload.links ?? []),
    43	      ...(payload.mentions ?? []),
    44	      ...(payload.extracted_links ?? []),
    45	      ...(payload.extracted_mentions ?? []),
    46	    ])
