    50	async function ensureDocumentExistsForWorkspace(docId: string, workspaceId: string) {
    51	  const result = await pool.query(
    52	    `SELECT id FROM documents
    53	     WHERE id = $1
    54	       AND workspace_id = $2
    55	       AND deleted_at IS NULL`,
    56	    [docId, workspaceId]
    57	  );
    58	
    59	  return result.rows.length > 0;
