    62	router.get('/:id/backlinks', authMiddleware, async (req: Request, res: Response) => {
    63	  const parsedId = uuidParamSchema.safeParse(req.params.id);
    64	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
    65	
    66	  const workspaceId = req.workspaceId;
    67	  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });
