    69	  const documentExists = await ensureDocumentExistsForWorkspace(parsedId.data, workspaceId);
    70	  if (!documentExists) return res.status(404).json({ error: 'Document not found' });
    71	
    72	  const result = await pool.query(
    73	    `SELECT d.id, COALESCE(d.document_type, 'document') AS document_type, d.title
    74	     FROM document_links dl
    75	     JOIN documents d ON dl.source_id = d.id
    76	     WHERE dl.target_id = $1
    77	       AND d.workspace_id = $2
    78	       AND d.deleted_at IS NULL
    79	       AND d.archived_at IS NULL
    80	     ORDER BY dl.created_at DESC, d.created_at DESC`,
    81	    [parsedId.data, workspaceId]
    82	  );
    83	
    84	  const backlinks = result.rows.map((row) => ({
    85	    id: row.id,
