    93	router.post('/:id/links', authMiddleware, async (req: Request, res: Response) => {
    94	  const parsedId = uuidParamSchema.safeParse(req.params.id);
    95	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
    96	
    97	  const workspaceId = req.workspaceId;
    98	  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });
    99	
   100	  const parsed = documentLinkSyncRequestSchema.safeParse(req.body);
   101	  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });
   102	
   103	  const sourceId = parsedId.data;
   104	  const sourceExists = await ensureDocumentExistsForWorkspace(sourceId, workspaceId);
   105	  if (!sourceExists) return res.status(404).json({ error: 'Document not found' });
   106	
   107	  const extractedIds = buildSyncedLinkSet(parsed.data).filter((id) => id !== sourceId);
   108	  const uniqueExtractedIds = Array.from(new Set(extractedIds));
   109	
   110	  const targetsResult = uniqueExtractedIds.length
   111	    ? await pool.query(
   112	        `SELECT id FROM documents
   113	         WHERE id = ANY($1::uuid[])
   114	           AND workspace_id = $2
   115	           AND deleted_at IS NULL
   116	           AND archived_at IS NULL`,
   117	        [uniqueExtractedIds, workspaceId]
   118	      )
   119	    : { rows: [] as Array<{ id: string }> };
   120	
   121	  if (targetsResult.rows.length !== uniqueExtractedIds.length) {
   122	    return res.status(400).json({ error: 'One or more target documents not found' });
   123	  }
   124	
   125	  const client = await pool.connect();
   126	  try {
   127	    await client.query('BEGIN');
   128	    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
   129	
   130	    if (uniqueExtractedIds.length > 0) {
   131	      const values = uniqueExtractedIds
   132	        .map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`)
   133	        .join(', ');
   134	      const params = uniqueExtractedIds.flatMap((targetId) => [sourceId, targetId]);
   135	      await client.query(
   136	        `INSERT INTO document_links (source_id, target_id)
   137	         VALUES ${values}
   138	         ON CONFLICT (source_id, target_id) DO UPDATE SET updated_at = NOW()`,
   139	        params
   140	      );
   141	    }
   142	
   143	    const responseRows = await client.query(
   144	      `SELECT DISTINCT target_id
   145	       FROM document_links
   146	       WHERE source_id = $1
   147	       ORDER BY target_id ASC`,
   148	      [sourceId]
   149	    );
   150	
   151	    await client.query('COMMIT');
   152	    return res.status(200).json({
   153	      success: true,
   154	      document_id: sourceId,
   155	      linked_document_ids: responseRows.rows.map((row) => row.target_id),
   156	      target_ids: responseRows.rows.map((row) => row.target_id),
   157	    } satisfies LinkSyncResponse & { target_ids: string[] });
   158	  } catch (err) {
   159	    await client.query('ROLLBACK');
   160	    throw err;
   161	  } finally {
   162	    client.release();
   163	  }
   164	});
