     7	const HREF_PATTERN = /(?:^|\s)\/((?:docs|issues|programs|sprints|team)\/[^\s)]+)|(?:^|\s)https?:\/\/[^\s)]+/g;
     8	const DOCUMENT_ID_PATTERN = /(docs|issues|programs|sprints|team)\/([a-zA-Z0-9-]+)/;
     9	
    10	export function getDocumentMentionsFromContent(content: unknown): DocumentMention[] {
    11	  const text = typeof content === 'string' ? content : JSON.stringify(content ?? '');
    12	  const matches = new Map<string, DocumentMention>();
    13	
    14	  for (const match of text.matchAll(HREF_PATTERN)) {
    15	    const href = match[0].trim();
    16	    const documentMatch = href.match(DOCUMENT_ID_PATTERN);
    17	    if (!documentMatch) continue;
    18	
    19	    const [, documentType, documentId] = documentMatch;
    20	    matches.set(documentId, { documentId, documentType });
    21	  }
    22	
    23	  return [...matches.values()];
    24	}
