import { Router, type Request, type Response } from 'express';
import { z } from 'zod';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';

const router = Router();

const uuidParamSchema = z.string().uuid();
const documentLinkSyncRequestSchema = z
  .object({
    target_ids: z.array(z.string().uuid()).optional(),
    links: z.array(z.string().uuid()).optional(),
    mentions: z.array(z.string().uuid()).optional(),
    extracted_links: z.array(z.string().uuid()).optional(),
    extracted_mentions: z.array(z.string().uuid()).optional(),
  })
  .refine(
    (payload) =>
      [payload.target_ids, payload.links, payload.mentions, payload.extracted_links, payload.extracted_mentions].some(
        (value) => Array.isArray(value)
      ),
    { message: 'At least one links or mentions array is required' }
  )
  .passthrough();

type BacklinkSummary = {
  id: string;
  title: string;
  type: string;
};

type LinkSyncResponse = {
  success: boolean;
  document_id: string;
  linked_document_ids: string[];
};

function buildSyncedLinkSet(payload: z.infer<typeof documentLinkSyncRequestSchema>) {
  return Array.from(
    new Set([
      ...(payload.target_ids ?? []),
      ...(payload.links ?? []),
      ...(payload.mentions ?? []),
      ...(payload.extracted_links ?? []),
      ...(payload.extracted_mentions ?? []),
    ])
  );
}

