   101	
   102	/**
   103	 * Handle image upload and insertion into editor
   104	 */
   105	async function handleImageUpload(
   106	  editor: Editor,
   107	  file: File,
   108	  options: ImageUploadOptions
   109	) {
   110	  const signal = options.abortController?.signal;
   111	
   112	  // Check if already aborted (e.g., user navigated away before upload started)
   113	  if (signal?.aborted) {
   114	    return;
   115	  }
   116	
   117	  options.onUploadStart?.(file);
   118	
   119	  // Generate unique upload ID for tracking navigation warnings
   120	  const uploadId = crypto.randomUUID();
   121	  registerUpload(uploadId, file.name);
   122	
   123	  // Insert image with local preview for immediate feedback
   124	  const previewUrl = URL.createObjectURL(file);
   125	  insertImage(editor, previewUrl, file.name);
   126	
   127	  // Revoke the preview URL once the image is replaced or upload stops
   128	  const cleanupPreview = () => URL.revokeObjectURL(previewUrl);
   129	
   130	  try {
   131	    const result = await uploadFile(
   132	      file,
   133	      (progress: UploadProgress) => {
   134	        // Update global tracker for navigation warning
   135	        updateUploadProgress(uploadId, progress.progress);
   136	      },
   137	      signal
   138	    );
   139	
   140	    // Check if aborted before updating the editor
   141	    // This prevents updating a stale editor after navigation
   142	    if (signal?.aborted) {
   143	      markUploadInactive(uploadId);
   144	      console.log('Image upload completed but was cancelled - not updating editor');
   145	      return;
   146	    }
   147	
   148	    const uploadedUrl = getUploadedImageUrl(result);
   149	    if (!isImageUploadSupportedUrl(uploadedUrl)) {
   150	      throw new Error('Upload did not return a usable image URL');
   151	    }
   152	
   153	    const { state, view } = editor;
   154	    const { doc } = state;
   155	
   156	    let imagePos: number | null = null;
   157	
   158	    doc.descendants((node: ProseMirrorNode, pos: number) => {
   159	      if (node.type.name === 'image' && node.attrs.src === previewUrl) {
   160	        imagePos = pos;
   161	        return false;
   162	      }
   163	      return true;
   164	    });
   165	
   166	    if (imagePos !== null) {
   167	      const transaction = state.tr.setNodeMarkup(imagePos, undefined, {
   168	        ...doc.nodeAt(imagePos)?.attrs,
   169	        src: uploadedUrl,
   170	      });
   171	      view.dispatch(transaction);
   172	    } else if (!signal?.aborted) {
   173	      // If the preview node is no longer present, insert the persisted image URL
   174	      insertImage(editor, uploadedUrl, file.name);
   175	    }
   176	
   177	    cleanupPreview();
   178	    // Upload complete - unregister from tracker
   179	    unregisterUpload(uploadId);
   180	    options.onUploadComplete?.(uploadedUrl);
   181	  } catch (error) {
   182	    // Upload failed - unregister from tracker
   183	    unregisterUpload(uploadId);
   184	    cleanupPreview();
   185	    // Don't report cancellation as an error - it's intentional
   186	    if (error instanceof DOMException && error.name === 'AbortError') {
   187	      console.log('Image upload cancelled');
   188	      return;
   189	    }
   190	
   191	    console.error('Image upload failed:', error);
   192	    options.onUploadError?.(
   193	      error instanceof Error ? error : new Error('Upload failed')
   194	    );
   195	
   196	    // Optionally remove the failed image or show error state
   197	    // For now, leave the preview as fallback
   198	  }
   199	}
   200	
   201	/**
   202	 * Convert a File to a data URL
   203	 */
   204	function fileToDataUrl(file: File): Promise<string> {
   205	  return new Promise((resolve, reject) => {
   206	    const reader = new FileReader();
   207	    reader.onload = () => resolve(reader.result as string);
   208	    reader.onerror = reject;
   209	    reader.readAsDataURL(file);
   210	  });
   211	}
   212	
   213	/**
   214	 * Trigger file picker for image upload
   215	 */
   216	function insertImage(editor: Editor, src: string, fileName: string) {
   217	  editor
   218	    .chain()
   219	    .focus()
   220	    .setImage({
   221	      src,
   222	      alt: fileName,
   223	      title: fileName,
   224	    })
   225	    .run();
   226	}
   227	
   228	export function triggerImageUpload(
   229	  editor: Editor,
   230	  options: ImageUploadOptions = {}
   231	) {
   232	  // Check if already aborted
   233	  if (options.abortController?.signal?.aborted) {
   234	    return;
   235	  }
   236	
   237	  const input = document.createElement('input');
   238	  input.type = 'file';
   239	  input.accept = 'image/*';
   240	  input.multiple = true;
   241	
   242	  input.onchange = () => {
   243	    // Check again in case it was aborted while file picker was open
   244	    if (options.abortController?.signal?.aborted) {
   245	      return;
   246	    }
   247	    const files = Array.from(input.files || []);
   248	    files.forEach((file) => {
   249	      handleImageUpload(editor, file, options);
   250	    });
   251	    input.remove();
   252	  };
   253	
   254	  input.click();
   255	}
