test('resolving a comment collapses thread and exposes resolved_at in UI/query data', async ({ page }) => {
  await createDocumentWithText(page, 'This highlighted text will be resolved and collapsed.')

  await selectText(page, 'resolved and collapsed')

  // Create comment thread with a reply so the resolved state has data to inspect.
  await page.getByRole('button', { name: 'Comment' }).click()
  const commentInput = page.getByRole('textbox', { name: 'Write a comment...' })
  await commentInput.fill('This will be resolved')
  await commentInput.press('Enter')
  await page.waitForTimeout(1500)

  const replyInput = page.getByRole('textbox', { name: 'Reply...' })
  await replyInput.fill('Reply before resolve')
  await replyInput.press('Enter')
  await page.waitForTimeout(1500)

  // Resolve the thread.
  await page.getByRole('button', { name: '✓' }).click()
  await page.waitForTimeout(1500)

  await expect(page.getByText('Resolved by Dev User')).toBeVisible({ timeout: 5000 })
  await expect(page.getByText('Show thread')).toBeVisible()
  await expect(page.getByText('This will be resolved')).not.toBeVisible()

  const resolvedAtFromUi = await page.evaluate(() => {
    const text = document.body.innerText
    const match = text.match(/resolved(?: at)?[:\s]+([^\n]+)/i)
    return match?.[1]?.trim() ?? null
  })
  expect(resolvedAtFromUi).toBeTruthy()

  const resolvedAtFromQuery = await page.evaluate(() => {
    const cache = (window as any).__REACT_QUERY_CLIENT__ || (window as any).__queryClient || null
    const queries = cache?.getQueryCache?.().getAll?.() ?? []
    for (const query of queries) {
      const data = query.state?.data
      if (!data) continue
      const candidates = Array.isArray(data) ? data : [data]
      for (const candidate of candidates) {
        if (candidate && typeof candidate === 'object' && 'resolved_at' in candidate && candidate.resolved_at) {
          return candidate.resolved_at
        }
        if (candidate && typeof candidate === 'object' && 'resolvedAt' in candidate && candidate.resolvedAt) {
          return candidate.resolvedAt
        }
      }
    }
    return null
  })
  expect(resolvedAtFromQuery).toBeTruthy()
})

