{"success":true,"content":"     1	import { Request, Response, NextFunction } from 'express';
     2	import crypto from 'crypto';
     3	import { pool } from '../db/client.js';
     4	import { SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS, ERROR_CODES, HTTP_STATUS } from '@ship/shared';
     5	
     6	// Extend Express Request to include session info
     7	declare global {
     8	  namespace Express {
     9	    interface Request {
    10	      sessionId?: string;
    11	      userId?: string;
    12	      workspaceId?: string;
    13	      isSuperAdmin?: boolean;
    14	      isApiToken?: boolean; // True when authenticated via API token
    15	    }
    16	  }
    17	}
    18	
    19	// Hash a token for comparison
    20	function hashToken(token: string): string {
    21	  return crypto.createHash('sha256').update(token).digest('hex');
    22	}
    23	
    24	// Validate API token and return user info if valid
    25	async function validateApiToken(token: string): Promise<{
    26	  userId: string;
    27	  workspaceId: string;
    28	  isSuperAdmin: boolean;
    29	  tokenId: string;
    30	} | null> {
    31	  const tokenHash = hashToken(token);
    32	
    33	  const result = await pool.query(
    34	    `SELECT t.id, t.user_id, t.workspace_id, t.expires_at, t.revoked_at, u.is_super_admin
    35	     FROM api_tokens t
    36	     JOIN users u ON t.user_id = u.id
    37	     WHERE t.token_hash = $1`,
    38	    [tokenHash]
    39	  );
    40	
    41	  const tokenRow = result.rows[0];
    42	
    43	  if (!tokenRow) return null;
    44	
    45	  // Check if revoked
    46	  if (tokenRow.revoked_at) return null;
    47	
    48	  // Check if expired
    49	  if (tokenRow.expires_at && new Date(tokenRow.expires_at) < new Date()) return null;
    50	
    51	  // Update last_used_at
    52	  await pool.query(
    53	    'UPDATE api_tokens SET last_used_at = NOW() WHERE id = $1',
    54	    [tokenRow.id]
    55	  );
    56	
    57	  return {
    58	    userId: tokenRow.user_id,
    59	    workspaceId: tokenRow.workspace_id,
    60	    isSuperAdmin: tokenRow.is_super_admin,
    61	    tokenId: tokenRow.id,
    62	  };
    63	}
    64	
    65	export async function authMiddleware(
    66	  req: Request,
    67	  res: Response,
    68	  next: NextFunction
    69	): Promise<void> {
    70	  // Check for Bearer token first (API token auth)
    71	  const authHeader = req.headers?.authorization;
    72	  if (authHeader && authHeader.startsWith('Bearer ')) {
    73	    const token = authHeader.slice(7);
    74	
    75	    try {
    76	      const tokenData = await validateApiToken(token);
    77	
    78	      if (!tokenData) {
    79	        res.status(HTTP_STATUS.UNAUTHORIZED).json({
    80	          success: false,
    81	          error: {
    82	            code: ERROR_CODES.UNAUTHORIZED,
    83	            message: 'Invalid or expired API token',
    84	          },
    85	        });
    86	        return;
    87	      }
    88	
    89	      // Attach token info to request
    90	      req.userId = tokenData.userId;
    91	      req.workspaceId = tokenData.workspaceId;
    92	      req.isSuperAdmin = tokenData.isSuperAdmin;
    93	      req.isApiToken = true;
    94	
    95	      next();
    96	      return;
    97	    } catch (error) {
    98	      console.error('API token auth error:', error);
    99	      res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
   100	        success: false,
   101	        error: {
   102	          code: ERROR_CODES.INTERNAL_ERROR,
   103	          message: 'Authentication failed',
   104	        },
   105	      });
   106	      return;
   107	    }
   108	  }
   109	
   110	  // Fall back to session cookie auth
   111	  const sessionId = req.cookies?.session_id;
   112	
   113	  if (!sessionId) {
   114	    res.status(HTTP_STATUS.UNAUTHORIZED).json({
   115	      success: false,
   116	      error: {
   117	        code: ERROR_CODES.UNAUTHORIZED,
   118	        message: 'No session found',
   119	      },
   120	    });
   121	    return;
   122	  }
   123	
   124	  try {
   125	    // Get session and check if it's valid
   126	    const result = await pool.query(
   127	      `SELECT s.id, s.user_id, s.workspace_id, s.expires_at, s.last_activity, s.created_at,
   128	              u.is_super_admin
   129	       FROM sessions s
   130	       JOIN users u ON s.user_id = u.id
   131	       WHERE s.id = $1`,
   132	      [sessionId]
   133	    );
   134	
   135	    const session = result.rows[0];
   136	
   137	    if (!session) {
   138	      res.status(HTTP_STATUS.UNAUTHORIZED).json({
   139	        success: false,
   140	        error: {
   141	          code: ERROR_CODES.UNAUTHORIZED,
   142	          message: 'Invalid session',
   143	        },
   144	      });
   145	      return;
   146	    }
   147	
   148	    const now = new Date();
   149	    const lastActivity = new Date(session.last_activity);
   150	    const createdAt = new Date(session.created_at);
   151	    const inactivityMs = now.getTime() - lastActivity.getTime();
   152	    const sessionAgeMs = now.getTime() - createdAt.getTime();
   153	
   154	    // Check 12-hour absolute session timeout (NIST SP 800-63B-4 AAL2)
   155	    if (sessionAgeMs > ABSOLUTE_SESSION_TIMEOUT_MS) {
   156	      await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
   157	
   158	      res.status(HTTP_STATUS.UNAUTHORIZED).json({
   159	        success: false,
   160	        error: {
   161	          code: ERROR_CODES.SESSION_EXPIRED,
   162	          message: 'Session expired. Please log in again.',
   163	        },
   164	      });
   165	      return;
   166	    }
   167	
   168	    // Check 15-minute inactivity timeout
   169	    if (inactivityMs > SESSION_TIMEOUT_MS) {
   170	      await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
   171	
   172	      res.status(HTTP_STATUS.UNAUTHORIZED).json({
   173	        success: false,
   174	        error: {
   175	          code: ERROR_CODES.SESSION_EXPIRED,
   176	          message: 'Session expired due to inactivity',
   177	        },
   178	      });
   179	      return;
   180	    }
   181	
   182	    // Verify user still has access to the workspace (unless super-admin)
   183	    if (session.workspace_id && !session.is_super_admin) {
   184	      const membershipResult = await pool.query(
   185	        'SELECT id FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2',
   186	        [session.workspace_id, session.user_id]
   187	      );
   188	
   189	      if (!membershipResult.rows[0]) {
   190	        // User no longer has access - delete session
   191	        await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
   192	
   193	        res.status(HTTP_STATUS.FORBIDDEN).json({
   194	          success: false,
   195	          error: {
   196	            code: ERROR_CODES.FORBIDDEN,
   197	            message: 'Access to this workspace has been revoked',
   198	          },
   199	        });
   200	        return;
   201	      }
   202	    }
   203	
   204	    // Update last activity
   205	    await pool.query(
   206	      'UPDATE sessions SET last_activity = $1 WHERE id = $2',
   207	      [now, sessionId]
   208	    );
   209	
   210	    // Refresh cookie with sliding expiration (throttled to avoid overhead)
   211	    // Only refresh if more than 60 seconds since last activity
