    14	
    15	export type UploadTrackerListener = (state: UploadTrackerState) => void;
    16	
    17	const activeUploads = new Map<string, UploadTrackerEntry>();
    18	const listeners = new Set<UploadTrackerListener>();
    19	
    20	function persistState() {
    21	  if (typeof window === 'undefined') {
    22	    return;
    23	  }
    24	
    25	  window.sessionStorage.setItem(storageKey, JSON.stringify(getUploadTrackerState()));
    26	}
    27	
    28	function emit() {
