    34	export function getUploadTrackerState(): UploadTrackerState {
    35	  return {
    36	    activeUploads: [...activeUploads.values()].sort((a, b) => a.startedAt - b.startedAt),
    37	  };
    38	}
    39	
    40	export function hasActiveUploads(): boolean {
    41	  return activeUploads.size > 0;
    42	}
    43	
    44	export function subscribeUploadTracker(listener: UploadTrackerListener): () => void {
    45	  listeners.add(listener);
    46	  listener(getUploadTrackerState());
    47	  return () => {
    48	    listeners.delete(listener);
    49	  };
    50	}
    51	
    52	export function startUploadTracking(id: string, label?: string): () => void {
    53	  activeUploads.set(id, { id, label, startedAt: Date.now() });
    54	  emit();
    55	  return () => {
    56	    if (activeUploads.delete(id)) {
    57	      emit();
    58	    }
    59	  };
    60	}
    61	
    62	export function stopUploadTracking(id: string): boolean {
    63	  const removed = activeUploads.delete(id);
    64	  if (removed) {
    65	    emit();
    66	  }
    67	  return removed;
