    92	export function useUploadNavigationWarning(options: { message?: string; when?: boolean } = {}) {
    93	  const state = useUploadTrackerState();
    94	  const enabled = options.when ?? state.activeUploads.length > 0;
    95	  const message = options.message ?? 'You have uploads in progress. Leaving now may cancel them.';
    96	
    97	  useEffect(() => {
    98	    if (!enabled || typeof window === 'undefined') {
    99	      return;
   100	    }
   101	
   102	    const handleBeforeUnload = (event: BeforeUnloadEvent) => {
   103	      event.preventDefault();
   104	      event.returnValue = message;
   105	      return message;
   106	    };
   107	
   108	    window.addEventListener('beforeunload', handleBeforeUnload);
   109	    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
   110	  }, [enabled, message]);
   111	
   112	  return useMemo(
   113	    () => ({
   114	      activeUploads: state.activeUploads,
   115	      hasActiveUploads: enabled,
   116	    }),
   117	    [enabled, state.activeUploads],
   118	  );
   119	}
