{"success":true,"content":"     1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
     2	import { EditorContent, useEditor } from '@tiptap/react';
     3	import StarterKit from '@tiptap/starter-kit';
     4	import Image from '@tiptap/extension-image';
     5	import { CommentMark } from '@/components/editor/CommentMark.js';
     6	import { ImageUploadExtension, triggerImageUpload } from '@/components/editor/ImageUpload.js';
     7	import { FileAttachmentExtension } from '@/components/editor/FileAttachment.js';
     8	import { CommentDisplayExtension } from '@/components/editor/CommentDisplay.js';
     9	import { useCommentsQuery } from '@/hooks/useCommentsQuery.js';
    10	import type { CommentThread } from '@/hooks/useCommentsQuery.js';
    11	
    12	interface LinkSyncResponse {
    13	  data?: unknown;
    14	  backlinks?: unknown;
    15	}
    16	
    17	export interface DocumentEditorProps {
    18	  documentId: string;
    19	  content: unknown;
    20	  onContentChange?: (content: unknown) => void;
    21	}
    22	
    23	export function DocumentEditor({ documentId, content, onContentChange }: DocumentEditorProps) {
    24	  const { comments = [], createComment, replyToComment, resolveComment } = useCommentsQuery(documentId);
    25	  const [pendingSelection, setPendingSelection] = useState<{ from: number; to: number } | null>(null);
    26	  const [pendingCommentId, setPendingCommentId] = useState<string | null>(null);
    27	  const editorRef = useRef<ReturnType<typeof useEditor> | null>(null);
    28	
    29	  const handleUploadImage = useCallback(() => {
    30	    if (!editorRef.current) return;
    31	    triggerImageUpload(editorRef.current, {
    32	      onUploadComplete: (uploadedUrl) => {
    33	        if (!editorRef.current) return;
    34	        editorRef.current.chain().focus().setImage({ src: uploadedUrl, alt: uploadedUrl, title: uploadedUrl }).run();
    35	      },
    36	    });
    37	  }, []);
    38	
    39	  const handleUploadFile = useCallback(() => {
    40	    if (!editorRef.current) return;
    41	    const input = document.createElement('input');
    42	    input.type = 'file';
    43	    input.multiple = true;
    44	    input.onchange = () => {
    45	      const files = Array.from(input.files || []);
    46	      files.forEach((file) => {
    47	        editorRef.current?.chain().focus().setFileAttachment({
    48	          filename: file.name,
    49	          url: '',
    50	          size: file.size,
    51	          mimeType: file.type || 'application/octet-stream',
    52	          uploading: true,
    53	        }).run();
    54	      });
    55	      input.remove();
    56	    };
    57	    input.click();
    58	  }, []);
    59	
    60	  const handleReply = useCallback(async (commentId: string, content: string) => {
    61	    await replyToComment({ documentId, parentId: commentId, content });
    62	  }, [documentId, replyToComment]);
    63	
    64	  const handleResolve = useCallback(async (commentId: string, resolved: boolean) => {
    65	    await resolveComment(commentId, resolved);
    66	    if (resolved && commentId === pendingCommentId) {
    67	      setPendingCommentId(null);
    68	    }
    69	  }, [pendingCommentId, resolveComment]);
    70	
    71	  const handleCreateComment = useCallback(async () => {
    72	    if (!editorRef.current || !pendingSelection) return;
    73	    const commentId = crypto.randomUUID();
    74	    editorRef.current.chain().focus().setTextSelection(pendingSelection).setComment(commentId).run();
    75	    setPendingCommentId(commentId);
    76	    await createComment({ documentId, content: 'New comment thread', commentId });
    77	  }, [createComment, documentId, pendingSelection]);
    78	
    79	  const handleSyncLinks = useCallback(async () => {
    80	    if (!editorRef.current) return;
    81	
    82	    const payload = editorRef.current.getJSON();
    83	    const response = await apiPost<LinkSyncResponse>(`/api/documents/${documentId}/links/sync`, {
    84	      content: payload,
    85	    });
    86	
    87	    const nextContent = (response.data ?? response.backlinks ?? payload) as unknown;
    88	    onContentChange?.(nextContent);
    89	  }, [documentId, onContentChange]);
    90	
    91	  const editor = useEditor({
    92	    extensions: [
    93	      StarterKit,
    94	      Image,
    95	      CommentMark.configure({
    96	        onCreateThread: (commentId) => {
    97	          setPendingCommentId(commentId);
    98	        },
    99	      }),
   100	      ImageUploadExtension,
   101	      FileAttachmentExtension,
   102	      CommentDisplayExtension.configure({
   103	        onReply: handleReply,
   104	        onResolve: handleResolve,
   105	        onCreateThread: (commentId) => setPendingCommentId(commentId),
   106	      }),
   107	    ],
   108	    content,
   109	    onUpdate: ({ editor }) => {
   110	      onContentChange?.(editor.getJSON());
   111	    },
   112	    onSelectionUpdate: ({ editor }) => {
   113	      if (editor.state.selection.empty) return;
   114	      const { from, to } = editor.state.selection;
   115	      setPendingSelection({ from, to });
   116	    },
   117	  });
   118	
   119	  useEffect(() => {
   120	    editorRef.current = editor;
   121	  }, [editor]);
   122	
   123	  const commentsCount = useMemo(() => comments.reduce((count: number, thread: CommentThread) => count + (thread.replies?.length || 0) + 1, 0), [comments]);
   124	
   125	  return (
   126	    <div className="flex h-full flex-col gap-2">
   127	      <div className="flex items-center gap-2 border-b border-border pb-2">
   128	        <button type="button" className="rounded bg-primary px-3 py-1 text-sm text-primary-foreground" onClick={handleUploadImage}>
   129	          Upload image
   130	        </button>
   131	        <button type="button" className="rounded bg-primary px-3 py-1 text-sm text-primary-foreground" onClick={handleUploadFile}>
   132	          Upload file
   133	        </button>
   134	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={handleCreateComment} disabled={!pendingSelection}>
   135	          Add comment
   136	        </button>
   137	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={handleSyncLinks}>
   138	          Sync links
   139	        </button>
   140	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={() => pendingCommentId && handleResolve(pendingCommentId, true)} disabled={!pendingCommentId}>
   141	          Resolve latest
   142	        </button>
   143	        <span className="text-xs text-muted">{commentsCount} comment entries</span>
   144	      </div>
   145	      <EditorContent editor={editor} />
   146	    </div>
   147	  );
   148	}
