     4	
     5	export interface UploadInfo {
     6	  id: string;
     7	  filename: string;
     8	  progress: number;
     9	  active: boolean;
    10	}
    11	
    12	export interface UploadTrackerSnapshot {
    13	  uploadCount: number;
    14	  activeUploads: UploadInfo[];
    15	}
    16	
    17	export interface UploadNavigationWarningState extends UploadTrackerSnapshot {
    18	  isBlocked: boolean;
    19	  proceed: () => void;
    20	  stay: () => void;
    21	}
    22	
    23	export interface UploadNavigationWarningHookState extends UploadNavigationWarningState {
    24	  isOpen: boolean;
    25	  message: string;
    26	}
    27	
    28	const activeUploads = new Map<string, UploadInfo>();
    29	const listeners = new Set<() => void>();
    30	let beforeUnloadListener: ((event: BeforeUnloadEvent) => void) | null = null;
    31	
    32	function hasWindow(): boolean {
    33	  return typeof window !== 'undefined';
    34	}
    35	
    36	function cloneUpload(upload: UploadInfo): UploadInfo {
    37	  return { ...upload };
    38	}
    39	
    40	function notifyListeners(): void {
    41	  listeners.forEach((listener) => listener());
    42	}
    43	
    44	function getUploadMessage(uploadCount: number): string {
    45	  return uploadCount === 1
    46	    ? '1 upload is still in progress.'
    47	    : `${uploadCount} uploads are still in progress.`;
    48	}
    49	
    50	function syncBeforeUnloadListener(): void {
    51	  if (!hasWindow()) return;
    52	
    53	  if (beforeUnloadListener) {
    54	    window.removeEventListener('beforeunload', beforeUnloadListener);
    55	    beforeUnloadListener = null;
    56	  }
    57	
    58	  if (!hasActiveUploads()) return;
    59	
    60	  beforeUnloadListener = (event: BeforeUnloadEvent) => {
    61	    if (!hasActiveUploads()) return;
    62	    event.preventDefault();
    63	    event.returnValue = getUploadMessage(getUploadCount());
    64	    return event.returnValue;
    65	  };
    66	
    67	  window.addEventListener('beforeunload', beforeUnloadListener);
    68	}
    69	
    70	export function registerUpload(id: string, filename: string): void {
    71	  activeUploads.set(id, { id, filename, progress: 0, active: true });
    72	  syncBeforeUnloadListener();
    73	  notifyListeners();
    74	}
    75	
    76	export function updateUploadProgress(id: string, progress: number): void {
    77	  const upload = activeUploads.get(id);
    78	  if (!upload) return;
    79	
    80	  upload.progress = progress;
    81	  upload.active = true;
    82	  syncBeforeUnloadListener();
    83	  notifyListeners();
    84	}
    85	
    86	export function markUploadInactive(id: string): void {
    87	  const upload = activeUploads.get(id);
    88	  if (!upload) return;
    89	
    90	  upload.active = false;
    91	  syncBeforeUnloadListener();
    92	  notifyListeners();
    93	}
    94	
    95	export function unregisterUpload(id: string): void {
    96	  activeUploads.delete(id);
    97	  syncBeforeUnloadListener();
    98	  notifyListeners();
    99	}
   100	
   101	export function clearUploads(): void {
   102	  activeUploads.clear();
   103	  syncBeforeUnloadListener();
   104	  notifyListeners();
   105	}
   106	
   107	export function getUploadCount(): number {
   108	  return Array.from(activeUploads.values()).filter((upload) => upload.active).length;
   109	}
   110	
   111	export function getActiveUploads(): UploadInfo[] {
   112	  return Array.from(activeUploads.values())
   113	    .filter((upload) => upload.active)
   114	    .map(cloneUpload);
   115	}
   116	
   117	export function hasActiveUploads(): boolean {
   118	  return getUploadCount() > 0;
   119	}
   120	
   121	export function getUploadSnapshot(): UploadTrackerSnapshot {
   122	  return {
   123	    uploadCount: getUploadCount(),
   124	    activeUploads: getActiveUploads(),
   125	  };
   126	}
   127	
   128	export function subscribeToUploads(listener: () => void): () => void {
   129	  listeners.add(listener);
   130	  listener();
   131	  return () => {
   132	    listeners.delete(listener);
   133	  };
   134	}
   135	
   136	export function getUploadNavigationWarningState(): UploadNavigationWarningState {
   137	  const snapshot = getUploadSnapshot();
   138	  return {
   139	    ...snapshot,
   140	    isBlocked: snapshot.uploadCount > 0,
   141	    proceed: clearUploads,
   142	    stay: () => undefined,
   143	  };
   144	}
   145	
   146	export function getUploadNavigationWarningMessage(uploadCount: number): string {
   147	  return getUploadMessage(uploadCount);
   148	}
   149	
   150	export function getUploadNavigationWarningHookState(): UploadNavigationWarningHookState {
   151	  const snapshot = getUploadSnapshot();
   152	  return {
   153	    ...snapshot,
   154	    isBlocked: snapshot.uploadCount > 0,
   155	    isOpen: snapshot.uploadCount > 0,
   156	    proceed: clearUploads,
   157	    stay: () => undefined,
   158	    message: getUploadNavigationWarningMessage(snapshot.uploadCount),
   159	  };
   160	}
   161	
   162	export function createUploadNavigationWarningGuard() {
   163	  return {
   164	    subscribe: subscribeToUploads,
   165	    getSnapshot: getUploadNavigationWarningHookState,
   166	  };
   167	}
