    15	// Resizable Image Component
    16	function ResizableImageComponent({ node, updateAttributes, selected }: NodeViewProps) {
    17	  const [isResizing, setIsResizing] = useState(false);
    18	  const imageRef = useRef<HTMLImageElement>(null);
    19	  const startX = useRef(0);
    20	  const startWidth = useRef(0);
    21	
    22	  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    23	    e.preventDefault();
    24	    e.stopPropagation();
    25	    setIsResizing(true);
    26	    startX.current = e.clientX;
    27	    startWidth.current = imageRef.current?.offsetWidth || 300;
    28	  }, []);
    29	
    30	  const handleMouseMove = useCallback((e: MouseEvent) => {
    31	    if (!isResizing) return;
    32	    const diff = e.clientX - startX.current;
    33	    const newWidth = Math.max(100, Math.min(800, startWidth.current + diff));
    34	    updateAttributes({ width: newWidth });
    35	  }, [isResizing, updateAttributes]);
    36	
    37	  const handleMouseUp = useCallback(() => {
    38	    setIsResizing(false);
    39	  }, []);
    40	
    41	  useEffect(() => {
    42	    if (isResizing) {
    43	      document.addEventListener('mousemove', handleMouseMove);
    44	      document.addEventListener('mouseup', handleMouseUp);
    45	      return () => {
    46	        document.removeEventListener('mousemove', handleMouseMove);
    47	        document.removeEventListener('mouseup', handleMouseUp);
    48	      };
    49	    }
    50	  }, [isResizing, handleMouseMove, handleMouseUp]);
    51	
    52	  const width = node.attrs.width || 'auto';
    53	
    54	  return (
    55	    <NodeViewWrapper className="relative inline-block my-4">
    56	      <div
    57	        className={`relative inline-block ${selected ? 'ring-2 ring-accent ring-offset-2 ring-offset-background' : ''}`}
    58	        style={{ width: width === 'auto' ? 'auto' : `${width}px` }}
    59	      >
    60	        <img
    61	          ref={imageRef}
    62	          src={node.attrs.src}
    63	          alt={node.attrs.alt || ''}
    64	          title={node.attrs.title}
    65	          className={cn('max-w-full rounded-lg block', node.attrs.src?.startsWith('blob:') ? 'opacity-80' : '')}
    66	          style={{ width: '100%', height: 'auto' }}
    67	          draggable={false}
    68	        />
    69	        {/* Resize handle - bottom right corner */}
    70	        {selected && (
    71	          <div
    72	            onMouseDown={handleMouseDown}
    73	            className="absolute bottom-0 right-0 w-4 h-4 bg-accent cursor-se-resize rounded-tl-sm opacity-80 hover:opacity-100 transition-opacity"
    74	            style={{ transform: 'translate(25%, 25%)' }}
    75	          />
    76	        )}
    77	      </div>
    78	      {/* Size indicator when resizing */}
    79	      {isResizing && (
    80	        <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 px-2 py-0.5 bg-muted text-xs text-muted-foreground rounded">
    81	          {width}px
    82	        </div>
    83	      )}
    84	    </NodeViewWrapper>
    85	  );
    86	}
    87	
    88	// Custom Resizable Image Extension
    89	export const ResizableImage = Node.create({
    90	  name: 'image',
    91	
    92	  group: 'block',
    93	
    94	  atom: true,
    95	
    96	  draggable: true,
    97	
    98	  addAttributes() {
