   100	      src: {
   101	        default: null,
   102	      },
   103	      alt: {
   104	        default: null,
   105	      },
   106	      title: {
   107	        default: null,
   108	      },
   109	      width: {
   110	        default: null,
   111	      },
   112	    };
   113	  },
   114	
   115	  parseHTML() {
