    14	import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
    15	import {
    16	  CallToolRequestSchema,
    17	  ListToolsRequestSchema,
    18	} from "@modelcontextprotocol/sdk/types.js";
    19	import type { Tool } from "@modelcontextprotocol/sdk/types.js";
    20	import { readFileSync, existsSync } from "fs";
    21	import { homedir } from "os";
    22	import { join } from "path";
    23	
    24	// ============== Configuration ==============
    25	
    26	interface Config {
    27	  token: string;
    28	  url: string;
    29	}
    30	
    31	function loadConfig(): Config {
    32	  const envPath = join(homedir(), ".claude", ".env");
    33	
    34	  if (!existsSync(envPath)) {
    35	    throw new Error("~/.claude/.env not found. Run /ship:auth first.");
    36	  }
    37	
    38	  const content = readFileSync(envPath, "utf-8");
    39	  const lines = content.split("\n");
    40	
    41	  let token = "";
    42	  let url = "http://localhost:3001";
    43	
    44	  for (const line of lines) {
    45	    if (line.startsWith("SHIP_API_TOKEN=")) {
    46	      token = line.substring("SHIP_API_TOKEN=".length).trim();
    47	    } else if (line.startsWith("SHIP_URL=")) {
    48	      url = line.substring("SHIP_URL=".length).trim();
    49	    }
    50	  }
    51	
    52	  if (!token) {
    53	    throw new Error("SHIP_API_TOKEN not found in ~/.claude/.env");
    54	  }
    55	
    56	  return { token, url };
    57	}
    58	
    59	// ============== OpenAPI Types (inline to avoid dependencies) ==============
    60	
    61	interface OpenAPIObject {
    62	  paths?: Record<string, PathItemObject>;
    63	  components?: {
    64	    schemas?: Record<string, SchemaObject>;
