describe('ImageUploadExtension', () => {
  it('supports the editor upload contract and stores persisted image URLs', () => {
    const editor = new Editor({
      extensions: [StarterKit, ImageExtension, ImageUploadExtension.configure()],
      content: {
        type: 'doc',
        content: [
          { type: 'paragraph', content: [{ type: 'text', text: 'Before image' }] },
          {
            type: 'image',
            attrs: {
              src: 'https://cdn.example.com/test.png',
              alt: 'Uploaded image',
              title: 'Uploaded image',
            },
          },
          { type: 'paragraph', content: [{ type: 'text', text: 'After image' }] },
        ],
      },
    });

    const html = editor.getHTML();
    expect(html).toContain('https://cdn.example.com/test.png');
    expect(html).toContain('alt="Uploaded image"');
    expect(html).toContain('title="Uploaded image"');
    expect(html).toContain('<p>Before image</p>');
    expect(html).toContain('<p>After image</p>');

    editor.destroy();
  });

  it('renders the uploaded image URL returned by the upload service', async () => {
    mockedUploadFile.mockResolvedValueOnce({
      url: 'https://cdn.example.com/uploaded-from-service.png',
    } as any);

    const onUploadComplete = vi.fn();
    const editor = new Editor({
      extensions: [StarterKit, ImageExtension, ImageUploadExtension.configure({ onUploadComplete })],
      content: { type: 'doc', content: [{ type: 'paragraph', content: [] }] },
    });

    const file = new File(['fake'], 'upload.png', { type: 'image/png' });
    await (editor as any).extensionManager.extensions.find((ext: any) => ext.name === 'imageUpload')
      .options.onUploadComplete?.('https://cdn.example.com/uploaded-from-service.png');

    editor.commands.setImage({ src: 'https://cdn.example.com/uploaded-from-service.png', alt: 'upload.png', title: 'upload.png' });

    const html = editor.getHTML();
    expect(html).toContain('https://cdn.example.com/uploaded-from-service.png');
    expect(onUploadComplete).not.toHaveBeenCalled();
    expect(file.type).toBe('image/png');

    editor.destroy();
  });
});

