export type UploadMode = 'presigned' | 'multipart';

export interface UploadRequestInput {
  filename: string;
  contentType?: string;
  size?: number;
  mode?: UploadMode;
}

export interface PresignedUploadResponse {
  mode: 'presigned';
  uploadUrl: string;
  method?: 'PUT' | 'POST';
  headers?: Record<string, string>;
  fileUrl?: string;
  key?: string;
}

export interface MultipartUploadResponse {
  mode: 'multipart';
  uploadUrl: string;
  method?: 'POST' | 'PUT';
  headers?: Record<string, string>;
  fields?: Record<string, string>;
  fileUrl?: string;
  key?: string;
}

export type UploadRequestResponse = PresignedUploadResponse | MultipartUploadResponse;

export interface UploadResult {
  fileUrl?: string;
  key?: string;
  response: Response;
}

export interface UploadProgressEvent {
  loaded: number;
  total?: number;
  percent?: number;
}

export type UploadProgressHandler = (progress: UploadProgressEvent) => void;

export interface TrackUploadProgressOptions {
  onProgress?: UploadProgressHandler;
}

const DEFAULT_UPLOAD_REQUEST_ENDPOINT = '/api/upload-request';

function getRequestHeaders(init?: RequestInit) {
  const headers = new Headers(init?.headers ?? {});
  if (!headers.has('Content-Type')) {
    headers.set('Content-Type', 'application/json');
  }
  return headers;
}

async function requestJson<T>(input: RequestInfo | URL, init?: RequestInit): Promise<T> {
  const response = await fetch(input, {
    ...init,
    headers: getRequestHeaders(init),
  });

  if (!response.ok) {
    const message = await response.text().catch(() => '');
    throw new Error(message || `Request failed with status ${response.status}`);
  }

  if (response.status === 204) {
    return undefined as T;
  }

  return (await response.json()) as T;
}

export async function requestUpload(input: UploadRequestInput): Promise<UploadRequestResponse> {
  return requestJson<UploadRequestResponse>(DEFAULT_UPLOAD_REQUEST_ENDPOINT, {
    method: 'POST',
    body: JSON.stringify(input),
  });
}

export function createUploadProgressTracker(onProgress?: UploadProgressHandler) {
  let lastLoaded = 0;
  let lastTotal: number | undefined;

  const emit = (loaded: number, total?: number) => {
    lastLoaded = loaded;
    lastTotal = total;
    onProgress?.({
      loaded,
      total,
      percent: total ? Math.round((loaded / total) * 100) : undefined,
    });
  };

  return {
    emit,
    get lastLoaded() {
      return lastLoaded;
    },
    get lastTotal() {
      return lastTotal;
    },
  };
}

export function trackUploadProgress(options: TrackUploadProgressOptions = {}) {
  const progress = createUploadProgressTracker(options.onProgress);
  const xhr = new XMLHttpRequest();

  xhr.upload.onprogress = (event: ProgressEvent<EventTarget>) => {
    const total = event.lengthComputable ? event.total : undefined;
    progress.emit(event.loaded, total);
  };

  return {
    xhr,
    ...progress,
  };
}

function createResponse(status: number, statusText: string) {
  return new Response(null, { status, statusText });
}

function toFormData(fields: Record<string, string>, file: File | Blob) {
  const form = new FormData();
  Object.entries(fields).forEach(([key, value]) => form.append(key, value));
  form.append('file', file);
  return form;
}

function isMultipartRequest(request?: UploadRequestResponse, fields?: Record<string, string>) {
  return request?.mode === 'multipart' || Boolean(fields) || Boolean(request && 'fields' in request && request.fields);
}

async function sendUpload(
  uploadUrl: string,
  options: {
    method: 'PUT' | 'POST';
    headers?: Record<string, string>;
    body: BodyInit;
    onProgress?: UploadProgressHandler;
  },
): Promise<Response> {
  const { xhr } = trackUploadProgress({ onProgress: options.onProgress });

  return await new Promise<Response>((resolve, reject) => {
    xhr.open(options.method, uploadUrl, true);
    Object.entries(options.headers ?? {}).forEach(([key, value]) => xhr.setRequestHeader(key, value));
    xhr.onload = () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        resolve(createResponse(xhr.status, xhr.statusText));
        return;
      }
      reject(new Error(`Upload failed with status ${xhr.status}`));
    };
    xhr.onerror = () => reject(new Error('Upload failed'));
    xhr.send(options.body);
  });
}

export async function uploadFile(
  file: File | Blob,
  options: {
    request?: UploadRequestResponse;
    uploadUrl?: string;
    method?: 'PUT' | 'POST';
    headers?: Record<string, string>;
    fields?: Record<string, string>;
    onProgress?: UploadProgressHandler;
  } = {},
): Promise<UploadResult> {
  const request = options.request;
  const uploadUrl = options.uploadUrl ?? request?.uploadUrl;
  if (!uploadUrl) {
    throw new Error('Missing upload URL');
  }

  const fields = options.fields ?? (request && 'fields' in request ? request.fields : undefined);
  const method = options.method ?? request?.method ?? (isMultipartRequest(request, fields) ? 'POST' : 'PUT');
  const headers = { ...(request?.headers ?? {}), ...(options.headers ?? {}) };

  const response = await sendUpload(uploadUrl, {
    method,
    headers,
    body: fields ? toFormData(fields, file) : file,
    onProgress: options.onProgress,
  });

  return {
    fileUrl: request?.fileUrl,
    key: request?.key,
    response,
  };
}
