    24	
    25	  doc.descendants((node: ProseMirrorNode, pos: number) => {
    26	    if (node.isText) {
    27	      for (const mark of node.marks) {
    28	        if (mark.type.name === 'commentMark' && mark.attrs.commentId) {
    29	          const commentId = mark.attrs.commentId;
    30	          const $pos = doc.resolve(pos);
    31	          const blockEnd = $pos.end(Math.max(1, $pos.depth));
    32	          positions.set(commentId, blockEnd);
    33	        }
    34	      }
    35	    }
    36	  });
