import { beforeEach, describe, expect, it, vi } from 'vitest';
import { act, renderHook, waitFor } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import type { PropsWithChildren } from 'react';
import { useCommentsQuery } from './useCommentsQuery';

const realFetch = globalThis.fetch;

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: { retry: false, gcTime: 0 },
      mutations: { retry: false },
    },
  });

  const wrapper = function Wrapper({ children }: PropsWithChildren) {
    return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>;
  };

  return { queryClient, wrapper };
}

function jsonResponse(data: unknown, status = 200): Promise<Response> {
  return Promise.resolve(
    new Response(JSON.stringify(data), {
      status,
      headers: { 'Content-Type': 'application/json' },
    }),
  );
}

describe('useCommentsQuery', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    globalThis.fetch = realFetch;
  });

  it('loads comment threads for a document and updates the cache after create', async () => {
    const fetchMock = vi.fn()
      .mockResolvedValueOnce(await jsonResponse({
        threads: [
          {
            id: 'thread-1',
            documentId: 'doc-1',
            parentId: null,
            content: 'Existing comment',
            status: 'open',
            createdAt: '2026-03-17T00:00:00.000Z',
            updatedAt: '2026-03-17T00:00:00.000Z',
            resolvedAt: null,
            replies: [],
          },
        ],
      }))
      .mockResolvedValueOnce(await jsonResponse({
        id: 'thread-2',
        documentId: 'doc-1',
        parentId: null,
        content: 'Created comment',
        status: 'open',
        createdAt: '2026-03-17T00:01:00.000Z',
        updatedAt: '2026-03-17T00:01:00.000Z',
        resolvedAt: null,
        replies: [],
      }));

    globalThis.fetch = fetchMock as typeof globalThis.fetch;

    const { queryClient, wrapper } = createWrapper();
    const { result } = renderHook(() => useCommentsQuery('doc-1'), { wrapper });

    await waitFor(() => expect(result.current.isSuccess).toBe(true));
    expect(result.current.comments).toHaveLength(1);

    await act(async () => {
      await result.current.createComment({ documentId: 'doc-1', content: 'Created comment' });
    });

    expect(queryClient.getQueryData(['comments', 'doc-1'])).toEqual([
      expect.objectContaining({ id: 'thread-2', content: 'Created comment' }),
      expect.objectContaining({ id: 'thread-1', content: 'Existing comment' }),
    ]);
  });

  it('updates replies, resolves comments, and removes deleted threads from cache', async () => {
    const fetchMock = vi.fn()
      .mockResolvedValueOnce(await jsonResponse({
        threads: [
          {
            id: 'thread-1',
            documentId: 'doc-1',
            parentId: null,
            content: 'Parent',
            status: 'open',
            createdAt: '2026-03-17T00:00:00.000Z',
            updatedAt: '2026-03-17T00:00:00.000Z',
            resolvedAt: null,
            replies: [],
          },
        ],
      }))
      .mockResolvedValueOnce(await jsonResponse({
        id: 'reply-1',
        documentId: 'doc-1',
        parentId: 'thread-1',
        content: 'Reply',
        status: 'open',
        createdAt: '2026-03-17T00:02:00.000Z',
        updatedAt: '2026-03-17T00:02:00.000Z',
        resolvedAt: null,
        replies: [],
      }))
      .mockResolvedValueOnce(await jsonResponse({
        id: 'thread-1',
        documentId: 'doc-1',
        parentId: null,
        content: 'Parent updated',
        status: 'resolved',
        createdAt: '2026-03-17T00:00:00.000Z',
        updatedAt: '2026-03-17T00:03:00.000Z',
        resolvedAt: '2026-03-17T00:03:00.000Z',
        replies: [],
      }))
      .mockResolvedValueOnce(await jsonResponse({}, 204));

    globalThis.fetch = fetchMock as typeof globalThis.fetch;

    const { queryClient, wrapper } = createWrapper();
    const { result } = renderHook(() => useCommentsQuery('doc-1'), { wrapper });

    await waitFor(() => expect(result.current.isSuccess).toBe(true));

    await act(async () => {
      await result.current.replyToComment({ documentId: 'doc-1', parentId: 'thread-1', content: 'Reply' });
      await result.current.updateComment({ commentId: 'thread-1', content: 'Parent updated' });
      await result.current.resolveComment({ commentId: 'thread-1', resolved: true });
      await result.current.deleteComment('thread-1');
    });

    expect(queryClient.getQueryData(['comments', 'doc-1'])).toEqual([]);
  });
});
